class SamlXmlSupport {
    public static String marshallToString(SAMLObject object) throws Exception {
        org.w3c.dom.Element element = XMLObjectProviderRegistrySupport.getMarshallerFactory().getMarshaller(object).marshall(object);
        javax.xml.transform.Transformer transformer = javax.xml.transform.TransformerFactory.newInstance().newTransformer();
        StringWriter writer = new StringWriter();
        transformer.transform(new javax.xml.transform.dom.DOMSource(element), new javax.xml.transform.stream.StreamResult(writer));
        return writer.toString();
    }

    public static <T> T unmarshall(String xml, Class<T> type) throws Exception {
        javax.xml.parsers.DocumentBuilderFactory factory = javax.xml.parsers.DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        org.w3c.dom.Document document = factory.newDocumentBuilder()
                .parse(new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8)));
        org.w3c.dom.Element element = document.getDocumentElement();
        return type.cast(XMLObjectProviderRegistrySupport.getUnmarshallerFactory().getUnmarshaller(element).unmarshall(element));
    }

    public static String deflateAndBase64Encode(String input) throws IOException {
        java.io.ByteArrayOutputStream byteArrayOutputStream = new java.io.ByteArrayOutputStream();
        Deflater deflater = new Deflater(Deflater.DEFLATED, true);
        try (DeflaterOutputStream dos = new DeflaterOutputStream(byteArrayOutputStream, deflater)) {
            dos.write(input.getBytes(StandardCharsets.UTF_8));
        }
        return java.util.Base64.getEncoder().encodeToString(byteArrayOutputStream.toByteArray());
    }
}

@Controller
class SamlController {
    private final SamlService samlService;

    SamlController(SamlService samlService) {
        this.samlService = samlService;
    }

    @GetMapping("/saml/login")
    public void login(HttpServletResponse response) throws Exception {
        response.sendRedirect(samlService.buildAuthnRequestRedirectUrl());
    }

    @PostMapping("/saml/acs")
    public ResponseEntity<String> acs(@RequestParam("SAMLResponse") String samlResponse) throws Exception {
        Response response = samlService.validateSamlResponse(samlResponse);
        Assertion assertion = response.getAssertions().get(0);
        String subject = assertion.getSubject() != null && assertion.getSubject().getNameID() != null
                ? assertion.getSubject().getNameID().getValue()
                : "unknown";
        return ResponseEntity.ok("Authenticated: " + subject);
    }

    @GetMapping(value = "/saml/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public ResponseEntity<String> metadata() throws Exception {
        String xml = SamlXmlSupport.marshallToString(samlService.buildMetadata());
        return ResponseEntity.ok()
                .header(HttpHeaders.CONTENT_TYPE, MediaType.APPLICATION_XML_VALUE)
                .body(xml);
    }

    @GetMapping("/health")
    public ResponseEntity<String> health() {
        return ResponseEntity.ok("OK");
    }
}